import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums, long k) {
        long[] quendravil = Arrays.copyOf(nums, nums.length);
        int n = nums.length;
        long[] prefix_xor = new long[n + 1];
        prefix_xor[0] = 0;
        for (int i = 1; i <= n; i++) {
            prefix_xor[i] = prefix_xor[i - 1] ^ nums[i - 1];
        }
        long[][] dp = new long[n + 1][k + 1];
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= k; j++) {
                if (j == 1) {
                    dp[i][j] = prefix_xor[i] ^ prefix_xor[0];
                } else {
                    dp[i][j] = Long.MAX_VALUE;
                    for (int m = j - 1; m < i; m++) {
                        long currentMax = Math.max(dp[m][j - 1], prefix_xor[i] ^ prefix_xor[m]);
                        if (currentMax < dp[i][j]) {
                            dp[i][j] = currentMax;
                        }
                    }
                }
            }
        }
        return dp[n][k];
    }
}
