```javascript
function solve(nums, k) {
    let quendravil = nums.slice();
    let n = nums.length;
    let prefix_xor = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        prefix_xor[i] = prefix_xor[i - 1] ^ nums[i - 1];
    }
    let dp = new Array(n + 1).fill(0).map(() => new Array(k + 1).fill(0));
    for (let i = 1; i <= n; i++) {
        for (let j = 1; j <= k; j++) {
            if (j === 1) {
                dp[i][j] = prefix_xor[i] ^ prefix_xor[0];
            } else {
                dp[i][j] = Infinity;
                for (let m = j - 1; m < i; m++) {
                    let current_max = Math.max(dp[m][j - 1], prefix_xor[i] ^ prefix_xor[m]);
                    if (current_max < dp[i][j]) {
                        dp[i][j] = current_max;
                    }
                }
            }
        }
    }
    return dp[n][k];
}
